import React, { useState, useEffect, useRef } from 'react';
import { useApp } from '../../App';
import { STATIONS, GARBAGE_TYPES, AREAS } from '../../data/mockData';
import LiveMap from '../../components/LiveMap';
import { timeAgo } from '../../utils/helpers';
import {
  Camera, MapPin, Send, ChevronLeft, CheckCircle2, AlertTriangle,
  Trash2, Recycle, Package, FlaskConical, Droplets, Clock,
  Navigation, Image, X, ZoomIn, Bell, Shield, Hash, Train
} from 'lucide-react';

const C = {
  navy:'#0A1628', blue:'#1565C0', blue2:'#1976D2', blueL:'#E3F2FD',
  green:'#2E7D32', greenL:'#E8F5E9', red:'#B71C1C', redL:'#FFEBEE',
  amber:'#E65100', amberL:'#FFF3E0', gray:'#546E7A', grayL:'#ECEFF1',
  text:'#0D1117', text2:'#3D4F61', text3:'#7A8FA6',
  white:'#fff', surface:'#F7F9FC', border:'#DDE3E9',
};

const GTYPE_ICONS = {
  'Plastic Waste': Trash2, 'Food Waste': Package, 'Abandoned Item': Package,
  'Chemical Spill': FlaskConical, 'Recyclable Waste': Recycle, 'Sewage / Water': Droplets,
};

const NAGPUR_BASE_LAT = 21.14580;
const NAGPUR_BASE_LNG = 79.08820;

const StatusBadge = ({ status }) => {
  const map = {
    NEW: { bg: C.amberL, c: C.amber, l: 'Pending' },
    ACCEPTED: { bg: C.blueL, c: C.blue, l: 'Accepted' },
    IN_PROGRESS: { bg: '#EDE7F6', c: '#4527A0', l: 'In Progress' },
    COMPLETED: { bg: C.greenL, c: C.green, l: 'Done' },
    QUERIED: { bg: '#FFF8E1', c: '#F57F17', l: 'Queried' },
    ESCALATED: { bg: C.redL, c: C.red, l: 'Escalated' }
  };
  const m = map[status] || map.NEW;
  return <span style={{ background: m.bg, color: m.c, padding: '3px 9px', borderRadius: 99, fontSize: 10.5, fontWeight: 700 }}>{m.l}</span>;
};

const TopBar = ({ title, onBack, right }) => (
  <div style={{ display: 'flex', alignItems: 'center', gap: 10, padding: '11px 16px', borderBottom: `1px solid ${C.border}`, background: C.white, flexShrink: 0 }}>
    {onBack && <button onClick={onBack} style={{ width: 34, height: 34, borderRadius: '50%', background: C.surface, border: `1px solid ${C.border}`, display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer' }}><ChevronLeft size={18} color={C.text2} /></button>}
    <span style={{ fontSize: 15, fontWeight: 700, flex: 1, color: C.text }}>{title}</span>
    {right}
  </div>
);

/* ─── LIVE TOAST NOTIFICATION ─── */
function LiveToast({ msg, onDone }) {
  useEffect(() => { const t = setTimeout(onDone, 4000); return () => clearTimeout(t); }, []);
  return (
    <div style={{ position: 'fixed', bottom: 80, left: '50%', transform: 'translateX(-50%)', background: C.navy, color: '#fff', padding: '10px 18px', borderRadius: 12, fontSize: 13, fontWeight: 600, display: 'flex', alignItems: 'center', gap: 8, zIndex: 9999, boxShadow: '0 4px 20px rgba(0,0,0,.3)', whiteSpace: 'nowrap', animation: 'slideUp .3s ease' }}>
      <Bell size={15} color="#42A5F5" />{msg}
    </div>
  );
}

/* ─── SCREEN 1: MAP HOME (WITH PROPER SYSTEM FILE INPUT CLICK) ─── */
function MapHome({ onPhotoSelected, myReports, liveToast }) {
  const { complaints } = useApp();
  const mapComplaints = complaints.filter(c => c.lat && c.lng);
  const [mapCenter, setMapCenter] = useState([NAGPUR_BASE_LAT, NAGPUR_BASE_LNG]);
  const fileInputRef = useRef(null);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (position) => { setMapCenter([position.coords.latitude, position.coords.longitude]); },
        () => console.log("Using static base map view anchor."),
        { enableHighAccuracy: true, timeout: 5000 }
      );
    }
  }, []);

  const handleFileChange = (e) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // Fast-capture location coordinates right at the context moment of upload trigger
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (p) => {
          const reader = new FileReader();
          reader.onloadend = () => {
            onPhotoSelected(reader.result, { lat: p.coords.latitude.toFixed(5), lng: p.coords.longitude.toFixed(5) });
          };
          reader.readAsDataURL(file);
        },
        () => {
          const reader = new FileReader();
          reader.onloadend = () => {
            onPhotoSelected(reader.result, { lat: NAGPUR_BASE_LAT.toFixed(5), lng: NAGPUR_BASE_LNG.toFixed(5) });
          };
          reader.readAsDataURL(file);
        },
        { enableHighAccuracy: true, timeout: 4000 }
      );
    } else {
      const reader = new FileReader();
      reader.onloadend = () => {
        onPhotoSelected(reader.result, { lat: NAGPUR_BASE_LAT.toFixed(5), lng: NAGPUR_BASE_LNG.toFixed(5) });
      };
      reader.readAsDataURL(file);
    }
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', flex: 1, overflow: 'hidden' }}>
      <div style={{ background: `linear-gradient(135deg,${C.navy} 0%,${C.blue} 100%)`, padding: '12px 18px 10px', flexShrink: 0 }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 6 }}>
          <div style={{ width: 20, height: 14, borderRadius: 2, overflow: 'hidden', display: 'flex', flexDirection: 'column', flexShrink: 0 }}>
            <div style={{ flex: 1, background: '#FF9933' }} /><div style={{ flex: 1, background: '#fff' }} /><div style={{ flex: 1, background: '#138808' }} />
          </div>
          <span style={{ color: 'rgba(255,255,255,.65)', fontSize: 10, fontWeight: 700, letterSpacing: 1, textTransform: 'uppercase' }}>Indian Railways · Nagpur Division</span>
        </div>
        <div style={{ color: '#fff', fontSize: 17, fontWeight: 800, marginBottom: 1 }}>Swachh Rail — Nagpur</div>
        <div style={{ color: 'rgba(255,255,255,.55)', fontSize: 11 }}>Report garbage near you · Native Camera Engine</div>
      </div>

      <div style={{ flex: 1, position: 'relative', minHeight: 200 }}>
        <LiveMap complaints={mapComplaints} center={mapCenter} zoom={14} height="100%" />
        
        {/* Native Hidden Shutter Access Node */}
        <input 
          type="file" 
          ref={fileInputRef} 
          accept="image/*" 
          capture="environment" 
          onChange={handleFileChange} 
          style={{ display: 'none' }} 
        />

        <button 
          onClick={() => fileInputRef.current?.click()} 
          style={{ position: 'absolute', bottom: 16, left: '50%', transform: 'translateX(-50%)', background: C.blue, color: C.white, padding: '13px 26px', borderRadius: 99, fontWeight: 800, fontSize: 14, border: 'none', cursor: 'pointer', boxShadow: `0 4px 20px ${C.blue}66`, display: 'flex', alignItems: 'center', gap: 8, whiteSpace: 'nowrap', zIndex: 500 }}
        >
          <Camera size={18} /> Open Camera & Click
        </button>

        <div style={{ position: 'absolute', top: 10, right: 10, background: 'rgba(10,22,40,.85)', color: '#fff', padding: '5px 12px', borderRadius: 8, fontSize: 11, fontWeight: 600, zIndex: 400, display: 'flex', alignItems: 'center', gap: 5 }}>
          <Shield size={12} color="#42A5F5" />{mapComplaints.length} active reports
        </div>
      </div>

      <div style={{ background: C.white, borderTop: `1px solid ${C.border}`, padding: '10px 14px', maxHeight: 185, overflowY: 'auto', flexShrink: 0 }}>
        <div style={{ fontSize: 12, fontWeight: 700, color: C.text, marginBottom: 8 }}>Your Reports ({myReports.length})</div>
        {myReports.length === 0 && (
          <div style={{ fontSize: 12, color: C.text3, textAlign: 'center', padding: '10px 0', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 6 }}>
            <MapPin size={13} color={C.text3} /> Tap the button above to launch camera snapshot
          </div>
        )}
        {myReports.map(r => (
          <div key={r.id} style={{ display: 'flex', alignItems: 'center', gap: 9, padding: '7px 0', borderBottom: `1px solid ${C.border}` }}>
            <div style={{ width: 40, height: 40, borderRadius: 8, overflow: 'hidden', flexShrink: 0, border: `1px solid ${C.border}`, background: C.surface }}>
              {r.photoURL ? <img src={r.photoURL} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover' }} /> : <div style={{ width: '100%', height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center' }}><Image size={14} color={C.text3} /></div>}
            </div>
            <div style={{ flex: 1, minWidth: 0 }}>
              <div style={{ fontSize: 10, fontFamily: 'monospace', color: C.text3 }}>{r.id}</div>
              <div style={{ fontSize: 12.5, fontWeight: 600, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{r.gtype} — PF {r.platformNo || 'N/A'}</div>
              <div style={{ fontSize: 11, color: C.text3, display: 'flex', alignItems: 'center', gap: 4 }}><Clock size={10} />{timeAgo(r.reportedAt)}<MapPin size={10} style={{ marginLeft: 4 }} />{r.area}</div>
            </div>
            <StatusBadge status={r.status} />
          </div>
        ))}
      </div>

      <div style={{ background: C.white, borderTop: `1px solid ${C.border}`, display: 'flex', flexShrink: 0 }}>
        {[{ Icon: MapPin, l: 'Map', on: true }, { Icon: Image, l: 'Reports' }, { Icon: Navigation, l: 'Help' }].map(b => (
          <button key={b.l} style={{ flex: 1, padding: '9px 4px', textAlign: 'center', cursor: 'pointer', border: 'none', background: 'none' }}>
            <b.Icon size={19} color={b.on ? C.blue : C.text3} style={{ display: 'block', margin: '0 auto 2px' }} />
            <span style={{ fontSize: 9.5, fontWeight: 700, color: b.on ? C.blue : C.text3 }}>{b.l}</span>
          </button>
        ))}
      </div>

      {liveToast && <LiveToast msg={liveToast} onDone={() => { }} />}
      <style>{`@keyframes slideUp{from{opacity:0;transform:translate(-50%,20px)}to{opacity:1;transform:translate(-50%,0)}}`}</style>
    </div>
  );
}

/* ─── SCREEN 2: TYPE PICKER ─── */
function PickerScreen({ photoURL, onSelect, onBack }) {
  const [sel, setSel] = useState(null);
  return (
    <div style={{ display: 'flex', flexDirection: 'column', flex: 1, overflow: 'hidden' }}>
      <TopBar title="What did you photograph?" onBack={onBack} />
      <div style={{ height: 110, background: '#000', flexShrink: 0, position: 'relative', overflow: 'hidden' }}>
        <img src={photoURL} alt="captured" style={{ width: '100%', height: '100%', objectFit: 'cover', opacity: .55 }} />
        <div style={{ position: 'absolute', inset: 0, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <div style={{ background: 'rgba(0,0,0,.6)', color: '#fff', padding: '5px 13px', borderRadius: 99, fontSize: 11, fontWeight: 600, display: 'flex', alignItems: 'center', gap: 5 }}>
            <Image size={13} /> Classify your photo
          </div>
        </div>
      </div>
      <div style={{ padding: '9px 14px 5px', color: C.text3, fontSize: 12, flexShrink: 0 }}>Select the closest match:</div>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3,1fr)', gap: 10, padding: 14, overflowY: 'auto', flex: 1 }}>
        {GARBAGE_TYPES.map(g => {
          const Icon = GTYPE_ICONS[g.label] || Trash2;
          return (
            <div key={g.id} onClick={() => setSel(g.id)}
              style={{ background: sel === g.id ? C.blueL : C.surface, border: `2px solid ${sel === g.id ? C.blue : C.border}`, borderRadius: 14, padding: '14px 8px', textAlign: 'center', cursor: 'pointer', transition: 'all .15s' }}
              onMouseDown={e => e.currentTarget.style.transform = 'scale(.95)'} onMouseUp={e => e.currentTarget.style.transform = 'scale(1)'}>
              <Icon size={27} color={sel === g.id ? C.blue : C.gray} style={{ margin: '0 auto 7px', display: 'block' }} />
              <div style={{ fontSize: 10.5, fontWeight: 700, color: sel === g.id ? C.blue : C.text2 }}>{g.label}</div>
              {g.severity === 'critical' && <div style={{ fontSize: 8.5, color: C.red, fontWeight: 700, marginTop: 2 }}>URGENT</div>}
            </div>
          );
        })}
      </div>
      <div style={{ padding: '0 14px 16px', flexShrink: 0 }}>
        <button disabled={!sel} onClick={() => onSelect(GARBAGE_TYPES.find(g => g.id === sel))}
          style={{ width: '100%', background: sel ? C.blue : C.grayL, color: sel ? C.white : C.gray, padding: '13px', borderRadius: 12, fontSize: 14.5, fontWeight: 800, border: 'none', cursor: sel ? 'pointer' : 'not-allowed', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 8 }}>
          Continue <ChevronLeft size={18} style={{ transform: 'rotate(180deg)' }} />
        </button>
      </div>
    </div>
  );
}

/* ─── SCREEN 3: CONFIRMATION WITH NEW ADAPTIVE RAILWAY FIELDS ─── */
function ConfirmScreen({ photoURL, gtype, gps, onSend, onBack }) {
  const [station, setStation] = useState(STATIONS[0].name);
  const [area, setArea] = useState(AREAS[0]);
  const [platformNo, setPlatformNo] = useState('');
  const [trainDetails, setTrainDetails] = useState('');
  const [coachPosition, setCoachPosition] = useState('');
  const [note, setNote] = useState('');
  const [zoom, setZoom] = useState(false);
  
  const Icon = GTYPE_ICONS[gtype.label] || Trash2;
  const latVal = gps?.lat || NAGPUR_BASE_LAT.toFixed(5);
  const lngVal = gps?.lng || NAGPUR_BASE_LNG.toFixed(5);

  return (
    <div style={{ display: 'flex', flexDirection: 'column', flex: 1, overflow: 'hidden' }}>
      <TopBar title="Confirm & Send" onBack={onBack} />
      <div style={{ flex: 1, overflowY: 'auto' }}>
        <div style={{ position: 'relative', background: '#000' }}>
          <img src={photoURL} alt="garbage" style={{ width: '100%', maxHeight: 210, objectFit: 'cover', display: 'block' }} />
          <button onClick={() => setZoom(true)} style={{ position: 'absolute', bottom: 8, right: 8, background: 'rgba(0,0,0,.55)', border: 'none', borderRadius: 8, padding: '4px 9px', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: 4, color: '#fff', fontSize: 11, fontWeight: 600 }}>
            <ZoomIn size={12} /> View full
          </button>
          <div style={{ position: 'absolute', top: 8, left: 8, background: 'rgba(0,0,0,.65)', color: '#fff', padding: '4px 10px', borderRadius: 99, fontSize: 11, fontWeight: 700, display: 'flex', alignItems: 'center', gap: 5 }}>
            <Icon size={12} /> {gtype.label}
          </div>
        </div>
        <div style={{ padding: '13px 15px' }}>
          {/* GPS Meta-Card */}
          <div style={{ background: C.greenL, border: `1px solid ${C.border}`, borderRadius: 10, padding: '8px 12px', display: 'flex', alignItems: 'center', gap: 8, marginBottom: 11 }}>
            <MapPin size={15} color={C.green} />
            <div>
              <div style={{ fontSize: 11.5, fontWeight: 700, color: C.green }}>Camera Location Captured</div>
              <div style={{ fontSize: 10.5, color: C.green, fontFamily: 'monospace' }}>{latVal}°N, {lngVal}°E</div>
            </div>
          </div>
          <div style={{ borderRadius: 10, overflow: 'hidden', marginBottom: 11, border: `1px solid ${C.border}` }}>
            <LiveMap singlePin singleCoords={{ lat: latVal, lng: lngVal }} height="120px" zoom={15} />
          </div>

          {/* Railway Station Selectors */}
          <div style={{ marginBottom: 10 }}>
            <label style={{ display: 'block', fontSize: 10.5, fontWeight: 700, color: C.text3, textTransform: 'uppercase', letterSpacing: .5, marginBottom: 5 }}>Nearest Station</label>
            <select value={station} onChange={e => setStation(e.target.value)} style={{ width: '100%', padding: '9px 11px', border: `1px solid ${C.border}`, borderRadius: 9, fontSize: 13, fontFamily: 'inherit', background: C.white }}>
              {STATIONS.map(s => <option key={s.id}>{s.name}</option>)}
            </select>
          </div>

          <div style={{ marginBottom: 10 }}>
            <label style={{ display: 'block', fontSize: 10.5, fontWeight: 700, color: C.text3, textTransform: 'uppercase', letterSpacing: .5, marginBottom: 5 }}>Exact Zone Area</label>
            <select value={area} onChange={e => setArea(e.target.value)} style={{ width: '100%', padding: '9px 11px', border: `1px solid ${C.border}`, borderRadius: 9, fontSize: 13, fontFamily: 'inherit', background: C.white }}>
              {AREAS.map(a => <option key={a}>{a}</option>)}
            </select>
          </div>

          {/* 🚄 EXTRA COMPREHENSIVE RAILWAY UTILITY FIELDS */}
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10, marginBottom: 10 }}>
            <div>
              <label style={{ display: 'block', fontSize: 10.5, fontWeight: 700, color: C.text3, textTransform: 'uppercase', letterSpacing: .5, marginBottom: 5 }}><Hash size={11} style={{ marginRight: 2, inlineSize: 'auto' }} /> Platform No</label>
              <input type="text" value={platformNo} onChange={e => setPlatformNo(e.target.value)} placeholder="e.g. 3" style={{ width: '100%', padding: '9px 11px', border: `1px solid ${C.border}`, borderRadius: 9, fontSize: 13, boxSizing: 'border-box' }} />
            </div>
            <div>
              <label style={{ display: 'block', fontSize: 10.5, fontWeight: 700, color: C.text3, textTransform: 'uppercase', letterSpacing: .5, marginBottom: 5 }}><Train size={11} style={{ marginRight: 2, inlineSize: 'auto' }} /> Coach Position</label>
              <input type="text" value={coachPosition} onChange={e => setCoachPosition(e.target.value)} placeholder="e.g. A1 / Near Engine" style={{ width: '100%', padding: '9px 11px', border: `1px solid ${C.border}`, borderRadius: 9, fontSize: 13, boxSizing: 'border-box' }} />
            </div>
          </div>

          <div style={{ marginBottom: 10 }}>
            <label style={{ display: 'block', fontSize: 10.5, fontWeight: 700, color: C.text3, textTransform: 'uppercase', letterSpacing: .5, marginBottom: 5 }}>Train Number / Name <span style={{ textTransform: 'none', fontWeight: 400 }}>(If on track)</span></label>
            <input type="text" value={trainDetails} onChange={e => setTrainDetails(e.target.value)} placeholder="e.g. 12290 / Nagpur Duronto" style={{ width: '100%', padding: '9px 11px', border: `1px solid ${C.border}`, borderRadius: 9, fontSize: 13, boxSizing: 'border-box' }} />
          </div>

          <div style={{ marginBottom: 10 }}>
            <label style={{ display: 'block', fontSize: 10.5, fontWeight: 700, color: C.text3, textTransform: 'uppercase', letterSpacing: .5, marginBottom: 5 }}>Context Note</label>
            <textarea value={note} onChange={e => setNote(e.target.value)} maxLength={200} placeholder="Describe what needs cleanup attention…" style={{ width: '100%', padding: '9px 11px', border: `1px solid ${C.border}`, borderRadius: 9, fontSize: 13, minHeight: 52, resize: 'none', fontFamily: 'inherit', boxSizing: 'border-box' }} />
          </div>

          {gtype.severity === 'critical' && (
            <div style={{ background: C.redL, border: '1px solid #FFCDD2', borderRadius: 8, padding: '8px 11px', fontSize: 12, color: C.red, fontWeight: 600, display: 'flex', gap: 7, alignItems: 'flex-start', marginBottom: 10 }}>
              <AlertTriangle size={14} style={{ flexShrink: 0, marginTop: 1 }} /> Critical profile tier flagged — escalated to station supervisor.
            </div>
          )}
        </div>
      </div>
      <div style={{ padding: '11px 14px 15px', borderTop: `1px solid ${C.border}`, display: 'flex', gap: 9, flexShrink: 0, background: C.white }}>
        <button onClick={onBack} style={{ background: C.surface, color: C.text2, padding: '11px 13px', borderRadius: 11, fontSize: 13, fontWeight: 600, border: `1px solid ${C.border}`, cursor: 'pointer' }}>Back</button>
        <button onClick={() => onSend({ gtype, station, area, platformNo, trainDetails, coachPosition, note, lat: latVal, lng: lngVal, photoURL })}
          style={{ flex: 1, background: C.blue, color: C.white, padding: '12px', borderRadius: 11, fontSize: 14, fontWeight: 800, border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 7, boxShadow: `0 2px 12px ${C.blue}55` }}>
          <Send size={16} /> Send Report
        </button>
      </div>
      {zoom && (
        <div onClick={() => setZoom(false)} style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,.93)', zIndex: 1000, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 16 }}>
          <img src={photoURL} alt="fullscreen" style={{ maxWidth: '100%', maxHeight: '100%', objectFit: 'contain', borderRadius: 8 }} />
          <button onClick={() => setZoom(false)} style={{ position: 'absolute', top: 16, right: 16, background: 'rgba(255,255,255,.15)', border: 'none', borderRadius: '50%', width: 36, height: 36, display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer' }}><X size={18} color="#fff" /></button>
        </div>
      )}
    </div>
  );
}

/* ─── SCREEN 4: SUCCESS PROFILE VIEW ─── */
function SuccessScreen({ ticket, photoURL, gps, gtype, station, platformNo, onDone }) {
  const Icon = GTYPE_ICONS[gtype?.label] || Trash2;
  const latVal = gps?.lat || NAGPUR_BASE_LAT.toFixed(5);
  const lngVal = gps?.lng || NAGPUR_BASE_LNG.toFixed(5);

  return (
    <div style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
      <div style={{ position: 'relative', flexShrink: 0 }}>
        <img src={photoURL} alt="reported" style={{ width: '100%', height: 160, objectFit: 'cover', display: 'block', filter: 'brightness(.6)' }} />
        <div style={{ position: 'absolute', inset: 0, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', gap: 6 }}>
          <CheckCircle2 size={44} color="#4CAF50" strokeWidth={1.5} />
          <div style={{ color: '#fff', fontSize: 19, fontWeight: 800 }}>Report Dispatched!</div>
          <div style={{ color: 'rgba(255,255,255,.7)', fontSize: 12 }}>Cleaning crew flagged instantly</div>
        </div>
      </div>
      <div style={{ flex: 1, overflowY: 'auto', padding: '16px 16px 0' }}>
        <div style={{ background: C.navy, color: '#fff', borderRadius: 14, padding: '13px 18px', marginBottom: 13 }}>
          <div style={{ fontSize: 9.5, opacity: .5, fontWeight: 700, letterSpacing: .5, textTransform: 'uppercase', marginBottom: 2 }}>Railway Ticket Token</div>
          <div style={{ fontSize: 21, fontWeight: 800, fontFamily: 'monospace', letterSpacing: 2 }}>{ticket}</div>
        </div>
        <div style={{ background: C.surface, border: `1px solid ${C.border}`, borderRadius: 12, padding: '11px 13px', marginBottom: 11 }}>
          {[
            ['Type', <span style={{ display: 'flex', alignItems: 'center', gap: 6 }}><Icon size={13} />{gtype?.label}</span>],
            ['Station Name', station],
            ['Platform Area', platformNo ? `Platform ${platformNo}` : 'General Compound'],
            ['GPS Node', `${latVal}, ${lngVal}`],
          ].map(([k, v], i, a) => (
            <div key={k} style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '7px 0', borderBottom: i < a.length - 1 ? `1px solid ${C.border}` : 'none' }}>
              <span style={{ fontSize: 12.5, color: C.text2 }}>{k}</span>
              <span style={{ fontSize: 12, fontWeight: 600, color: C.text, maxWidth: 180, textAlign: 'right' }}>{v}</span>
            </div>
          ))}
        </div>
        <div style={{ borderRadius: 12, overflow: 'hidden', marginBottom: 11, border: `1px solid ${C.border}` }}>
          <LiveMap singlePin singleCoords={{ lat: latVal, lng: lngVal }} height="120px" zoom={15} />
        </div>
      </div>
      <div style={{ padding: '11px 16px 18px', borderTop: `1px solid ${C.border}`, flexShrink: 0, background: C.white }}>
        <button onClick={onDone} style={{ width: '100%', background: C.blue, color: C.white, padding: '13px', borderRadius: 12, fontSize: 14, fontWeight: 700, border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 7 }}>
          <MapPin size={16} /> Back to Live Map
        </button>
      </div>
    </div>
  );
}

/* ─── MAIN USER PORTAL RUNTIME ROOT CONTROLLER ─── */
export default function UserPortal() {
  const { addComplaint } = useApp();
  const [screen, setScreen] = useState('map');
  const [photoURL, setPhotoURL] = useState(null);
  const [gps, setGps] = useState(null);
  const [gtype, setGtype] = useState(null);
  const [ticket, setTicket] = useState(null);
  const [sentData, setSentData] = useState(null);
  const [myReports, setMyReports] = useState([]);
  const [liveToast, setLiveToast] = useState('');

  const handlePhotoCaptured = (url, coordinates) => {
    setPhotoURL(url);
    setGps(coordinates);
    setScreen('picker');
  };

  const handleSend = (data) => {
    const id = addComplaint({
      gtype: data.gtype.label,
      emoji: '📷',
      severity: data.gtype.severity,
      station: data.station,
      area: data.area,
      platformNo: data.platformNo,
      trainDetails: data.trainDetails,
      coachPosition: data.coachPosition,
      note: data.note,
      lat: parseFloat(data.lat),
      lng: parseFloat(data.lng),
      photoURL: data.photoURL,
    });

    setTicket(id);
    setSentData(data);
    setMyReports(p => [{
      id, gtype: data.gtype.label, emoji: '📷',
      area: data.area, photoURL: data.photoURL, platformNo: data.platformNo,
      station: { name: data.station }, status: 'NEW', reportedAt: new Date(),
      lat: parseFloat(data.lat), lng: parseFloat(data.lng),
    }, ...p]);

    setLiveToast('Complaint registered with high-accuracy live map logs!');
    setScreen('success');
  };

  return (
    <div style={{ width: '100%', maxWidth: 430, margin: '0 auto', background: C.white, display: 'flex', flexDirection: 'column', height: '100vh', fontFamily: 'DM Sans,system-ui,sans-serif', overflow: 'hidden' }}>
      {screen === 'map' && <MapHome onPhotoSelected={handlePhotoCaptured} myReports={myReports} liveToast={liveToast} />}
      {screen === 'picker' && <PickerScreen photoURL={photoURL} onSelect={g => { setGtype(g); setScreen('confirm'); }} onBack={() => setScreen('map')} />}
      {screen === 'confirm' && gtype && <ConfirmScreen photoURL={photoURL} gtype={gtype} gps={gps} onSend={handleSend} onBack={() => setScreen('picker')} />}
      {screen === 'success' && ticket && sentData && <SuccessScreen ticket={ticket} photoURL={photoURL} gps={gps} gtype={gtype} station={sentData.station} platformNo={sentData.platformNo} onDone={() => { setLiveToast(''); setScreen('map'); }} />}
    </div>
  );
}
